[{"type": "modify", "target_text": "10.1 Supplier shall indemnify, defend and hold harmless Buyer, its Affiliates, and their respective officers, directors, employees and agents from and against any and all claims, losses, damages, liabilities, costs and expenses (including reasonable legal fees on a full indemnity basis) arising out of or in connection with:

